def range_summary(nums):
    if not nums:
        return ""

    run = []
    result = []

    for num in sorted(set(nums)):
        if run and num == run[-1] + 1:
            run.append(num)
        else:
            if len(run) > 1:
                result.append(f"{run[0]}-{run[-1]}")
            else:
                result.append(str(run[0]))
            run = [num]

    if len(run) > 1:
        result.append(f"{run[0]}-{run[-1]}")
    else:
        result.append(str(run[0]))

    return ",".join(result)
